template <typename Inst>
inline void execute_v_addc_co_u32_vop2([[maybe_unused]] Inst &inst,
                                       [[maybe_unused]] Wavefront &wf) {
  ROCJITSU_TRY_SIMD_VOP2_CARRY([](auto a, auto b, auto cin) {
    auto t1 = a + b;
    auto c1 = t1 < a;
    auto t2 = t1 + cin;
    auto c2 = t2 < t1;
    return make_simd_carry(t2, c1 | c2);
  });
  uint64_t exec = wf.exec();
  uint64_t vcc = 0;
  for (uint32_t lane = 0; lane < wf.wf_size(); ++lane) {
    if (!(exec & (1ULL << lane)))
      continue;
    inst.vdst.write_lane(wf, lane, [&]() {
      uint64_t w = static_cast<uint64_t>(inst.src0.read_lane(wf, lane)) +
                   static_cast<uint64_t>(inst.vsrc1.read_lane(wf, lane)) +
                   static_cast<uint64_t>(((wf.vcc() >> lane) & 1));
      if (w > 0xFFFFFFFFULL)
        vcc |= (1ULL << lane);
      else
        vcc &= ~(1ULL << lane);
      return static_cast<uint32_t>(w);
    }());
  }
  wf.set_vcc(vcc);
}

